package com.socialblog.follower.application;import com.fasterxml.jackson.databind.*;import com.socialblog.follower.domain.*;import com.socialblog.follower.repository.*;import io.micrometer.core.instrument.Metrics;import org.springframework.boot.autoconfigure.condition.ConditionalOnProperty;import org.springframework.kafka.annotation.KafkaListener;import org.springframework.stereotype.Component;import org.springframework.transaction.annotation.Transactional;import java.util.UUID;@Component @ConditionalOnProperty(name="app.kafka.consumer-enabled",havingValue="true",matchIfMissing=true)public class UserEventConsumer{private final ObjectMapper json;private final UserProjectionRepository users;private final ProcessedEventRepository processed;public UserEventConsumer(ObjectMapper j,UserProjectionRepository u,ProcessedEventRepository p){json=j;users=u;processed=p;}@KafkaListener(topics="users.events")@Transactional public void consume(String raw)throws Exception{JsonNode e=json.readTree(raw);UUID event=UUID.fromString(e.path("eventId").asText());if(processed.existsById(event))return;String type=e.path("eventType").asText();if(!type.equals("UserRegistered"))return;JsonNode payload=e.path("payload");UUID user=UUID.fromString(payload.path("userId").asText());String name=payload.path("displayName").asText();UserProjection projection=users.findById(user).orElseGet(()->new UserProjection(user,true,name));projection.update(true,name);users.save(projection);processed.save(new ProcessedEvent(event,type));Metrics.counter("socialblog.kafka.consumer.events","topic","users.events","eventType",type,"outcome","processed").increment();}}
